ps.pstext:
if !IsFeatureImplemented(FEAT_LSUI) then EndOfDecode(Decode_UNDEF); end;

let t : integer{} = UInt(Rt);
let t2 : integer{} = UInt(Rt2);
let n : integer{} = UInt(Rn);
let nontemporal : boolean = TRUE;
let datasize : integer{} = 64;
let offset : bits(64) = LSL(SignExtend{64}(imm7), 3);
let tagchecked : boolean = n != 31;

var address : bits(64);
let dbytes : integer{} = datasize DIV 8;
let privileged : boolean = AArch64_IsUnprivAccessPriv();
let ispair : boolean = TRUE;
let accdesc : AccessDescriptor = CreateAccDescGPR(MemOp_STORE, nontemporal, privileged,
                                                  tagchecked, ispair, t, t2);
if n == 31 then
    CheckSPAlignment();
    address = SP{64}();
else
    address = X{64}(n);
end;

address = AddressAdd(address, offset, accdesc);
let data : bits(2*datasize)= (if BigEndian(accdesc.acctype)
                                   then X{datasize}(t) ::X{datasize}(t2)
                                   else X{datasize}(t2)::X{datasize}(t));
Mem{2*datasize}(address, accdesc) = data;
